import { GatewayConfig } from '../gatewayGenerator';

export function generateMidiHandler(config: GatewayConfig): string {
  const midiConfig = config.protocols.find(p => p.type === 'midi') || config.protocols[0];
  const autoLearn = midiConfig?.settings?.autoLearn !== false;
  
  // Build variable mappings from configuration
  let variableDefinitions = '';
  
  if (midiConfig?.settings?.variables && midiConfig.settings.variables.length > 0) {
    variableDefinitions = midiConfig.settings.variables
      .map((v: any, index: number) => {
        const messageType = v.messageType || 'note_on';
        const channel = v.channel !== undefined ? v.channel : null;
        const note = v.note !== undefined ? v.note : null;
        const controller = v.controller !== undefined ? v.controller : null;
        
        return `    "${v.name}": {
      messageType: "${messageType}",
      channel: ${channel !== null ? channel : 'null'},
      note: ${note !== null ? note : 'null'},
      controller: ${controller !== null ? controller : 'null'},
      description: "${v.description || 'MIDI variable'}",
      dataType: "${v.dataType || 'int'}",
      value: 0,
      lastUpdate: null
    }${index < midiConfig.settings.variables.length - 1 ? ',' : ''}`;
      })
      .join('\n');
  }

  return `/**
 * MIDI Protocol Handler - Node.js Implementation
 * Generated by Industrial Gateway Builder
 * 
 * This module provides MIDI device connectivity and exposes
 * MIDI messages as variables to the REST API.
 * 
 * Note: This module requires the 'midi' npm package which needs native compilation.
 * If the module fails to load, this handler will operate in stub mode.
 */

let midi;
try {
  midi = require('midi');
} catch (err) {
  console.error('Failed to load MIDI module:', err.message);
  console.error('MIDI functionality will not be available.');
}

class MidiHandler {
  constructor(config, logger) {
    this.config = config;
    this.logger = logger;
    this.enabled = config.enabled && !!midi;
    this.autoLearn = ${autoLearn};
    
    if (!midi) {
      this.logger.warn('MIDI module not available - handler disabled');
      return;
    }
    
    // MIDI input/output ports
    this.input = new midi.Input();
    this.output = new midi.Output();
    
    // Variable store with pre-configured and learned variables
    this.variables = {
${variableDefinitions}
    };
    
    // Store for auto-learned MIDI messages
    this.learnedMessages = new Map();
    
    // Device information
    this.devices = {
      inputs: [],
      outputs: []
    };
    
    if (this.enabled) {
      this.initialize();
    }
  }

  initialize() {
    if (!midi) {
      this.logger.error('Cannot initialize MIDI: module not available');
      return;
    }
    
    try {
      this.logger.info('🎹 Initializing MIDI Handler...');
      
      // Discover devices
      this.discoverDevices();
      
      // Open first available input device
      if (this.devices.inputs.length > 0) {
        this.openInput(0);
      } else {
        this.logger.warn('⚠️  No MIDI input devices found');
      }
      
      // List output devices (optional)
      if (this.devices.outputs.length > 0) {
        this.logger.info(\`Found \${this.devices.outputs.length} MIDI output device(s)\`);
      }
      
    } catch (error) {
      this.logger.error(\`Failed to initialize MIDI: \${error.message}\`);
      this.enabled = false;
    }
  }

  discoverDevices() {
    // Discover input devices
    const inputCount = this.input.getPortCount();
    for (let i = 0; i < inputCount; i++) {
      const deviceName = this.input.getPortName(i);
      this.devices.inputs.push({ index: i, name: deviceName });
      this.logger.info(\`  📥 MIDI Input \${i}: \${deviceName}\`);
    }
    
    // Discover output devices
    const outputCount = this.output.getPortCount();
    for (let i = 0; i < outputCount; i++) {
      const deviceName = this.output.getPortName(i);
      this.devices.outputs.push({ index: i, name: deviceName });
      this.logger.info(\`  📤 MIDI Output \${i}: \${deviceName}\`);
    }
  }

  openInput(portIndex) {
    try {
      const deviceName = this.input.getPortName(portIndex);
      
      // Set up message callback
      this.input.on('message', (deltaTime, message) => {
        this.handleMidiMessage(message);
      });
      
      // Open the port
      this.input.openPort(portIndex);
      this.logger.info(\`✅ Opened MIDI input: \${deviceName}\`);
      
    } catch (error) {
      this.logger.error(\`Failed to open MIDI input: \${error.message}\`);
    }
  }

  handleMidiMessage(message) {
    try {
      // Parse MIDI message [status, data1, data2]
      const [status, data1, data2] = message;
      
      // Extract message type and channel
      const messageType = status & 0xF0;
      const channel = status & 0x0F;
      
      const parsedMsg = this.parseMidiMessage(messageType, channel, data1, data2);
      
      if (!parsedMsg) return;
      
      // Check if this message matches any configured variables
      let matched = false;
      for (const [varName, varConfig] of Object.entries(this.variables)) {
        if (this.messageMatchesConfig(parsedMsg, varConfig)) {
          this.variables[varName].value = parsedMsg.value;
          this.variables[varName].lastUpdate = new Date().toISOString();
          matched = true;
          this.logger.debug(\`Updated variable '\${varName}' = \${parsedMsg.value}\`);
        }
      }
      
      // Auto-learn mode: store new unique messages
      if (this.autoLearn && !matched) {
        const msgKey = this.createMessageKey(parsedMsg);
        const varName = \`MIDI_\${msgKey}\`;
        
        if (!this.learnedMessages.has(msgKey)) {
          this.learnedMessages.set(msgKey, {
            name: varName,
            ...parsedMsg,
            description: \`Auto-learned \${parsedMsg.type}\`,
            lastUpdate: new Date().toISOString()
          });
          this.logger.info(\`📖 Auto-learned MIDI message: \${varName}\`);
        } else {
          // Update existing learned message
          const learned = this.learnedMessages.get(msgKey);
          learned.value = parsedMsg.value;
          learned.lastUpdate = new Date().toISOString();
        }
      }
    } catch (error) {
      this.logger.error(\`Error processing MIDI message: \${error.message}\`);
    }
  }

  parseMidiMessage(messageType, channel, data1, data2) {
    const parsed = {
      type: '',
      channel,
      value: 0
    };
    
    switch (messageType) {
      case 0x90: // Note On
        if (data2 === 0) {
          parsed.type = 'note_off';
          parsed.note = data1;
          parsed.value = 0;
        } else {
          parsed.type = 'note_on';
          parsed.note = data1;
          parsed.value = data2; // velocity
        }
        break;
        
      case 0x80: // Note Off
        parsed.type = 'note_off';
        parsed.note = data1;
        parsed.value = 0;
        break;
        
      case 0xB0: // Control Change
        parsed.type = 'control_change';
        parsed.controller = data1;
        parsed.value = data2;
        break;
        
      case 0xE0: // Pitch Bend
        parsed.type = 'pitchwheel';
        parsed.value = (data2 << 7) | data1;
        break;
        
      case 0xA0: // Aftertouch
        parsed.type = 'aftertouch';
        parsed.note = data1;
        parsed.value = data2;
        break;
        
      case 0xC0: // Program Change
        parsed.type = 'program_change';
        parsed.value = data1;
        break;
        
      case 0xD0: // Channel Pressure
        parsed.type = 'channel_pressure';
        parsed.value = data1;
        break;
        
      default:
        return null;
    }
    
    return parsed;
  }

  createMessageKey(msg) {
    const parts = [msg.type, \`CH\${msg.channel}\`];
    
    if (msg.note !== undefined) {
      parts.push(\`N\${msg.note}\`);
    }
    
    if (msg.controller !== undefined) {
      parts.push(\`CC\${msg.controller}\`);
    }
    
    return parts.join('_');
  }

  messageMatchesConfig(msg, config) {
    // Check message type
    if (config.messageType !== msg.type) {
      return false;
    }
    
    // Check channel (null means any channel)
    if (config.channel !== null && config.channel !== msg.channel) {
      return false;
    }
    
    // Check note (for note messages)
    if (msg.note !== undefined) {
      if (config.note !== null && config.note !== msg.note) {
        return false;
      }
    }
    
    // Check controller (for control_change messages)
    if (msg.controller !== undefined) {
      if (config.controller !== null && config.controller !== msg.controller) {
        return false;
      }
    }
    
    return true;
  }

  getVariableList() {
    const configuredVars = Object.keys(this.variables).map(name => ({
      name,
      ...this.variables[name]
    }));
    
    const learnedVars = Array.from(this.learnedMessages.values());
    
    return [...configuredVars, ...learnedVars];
  }

  async readVariable(variableName, device) {
    // Check configured variables
    if (this.variables[variableName]) {
      const varData = this.variables[variableName];
      return {
        value: varData.value,
        dataType: varData.dataType,
        quality: 'good',
        timestamp: varData.lastUpdate || new Date().toISOString()
      };
    }
    
    // Check learned messages
    for (const [key, learned] of this.learnedMessages.entries()) {
      if (learned.name === variableName) {
        return {
          value: learned.value,
          dataType: 'int',
          quality: 'good',
          timestamp: learned.lastUpdate
        };
      }
    }
    
    throw new Error(\`Variable '\${variableName}' not found\`);
  }

  async writeVariable(variableName, value, device) {
    // MIDI variables are typically read-only from device input
    // But we could support sending MIDI messages out
    throw new Error('Write operation not supported for MIDI variables');
  }

  getData(device) {
    const allVars = {};
    
    // Add configured variables
    for (const [name, data] of Object.entries(this.variables)) {
      allVars[name] = data.value;
    }
    
    // Add learned messages
    for (const [key, learned] of this.learnedMessages.entries()) {
      allVars[learned.name] = learned.value;
    }
    
    return allVars;
  }

  close() {
    if (!midi) {
      return;
    }
    
    try {
      if (this.input && this.input.isPortOpen()) {
        this.input.closePort();
        this.logger.info('Closed MIDI input port');
      }
      
      if (this.output && this.output.isPortOpen()) {
        this.output.closePort();
        this.logger.info('Closed MIDI output port');
      }
    } catch (error) {
      this.logger.error(\`Error closing MIDI ports: \${error.message}\`);
    }
  }
}

module.exports = MidiHandler;
`;
